  1→package agent
  2→
  3→import (
  4→	"time"
  5→
  6→	"github.com/entireio/cli/cmd/entire/cli/agent/types"
  7→)
  8→
  9→// AgentSession represents a coding session's data.
 10→// Each agent stores data in its native format (JSONL, SQLite, Markdown, etc.)
 11→// and only the originating agent can read/write it.
 12→//
 13→// Design: Sessions are NOT interoperable between agents. A session created by
 14→// Claude Code can only be read/written by Claude Code. This simplifies the
 15→// implementation as we don't need format conversion.
 16→//
 17→//nolint:revive // AgentSession is clearer than Session in context of the package
 18→type AgentSession struct {
 19→	SessionID  string
 20→	AgentName  types.AgentName
 21→	RepoPath   string
 22→	SessionRef string // Path/reference to session in agent's storage
 23→	StartTime  time.Time
 24→
 25→	// NativeData holds the session content in the agent's native format.
 26→	// Only the originating agent can interpret this data.
 27→	// Examples:
 28→	//   - Claude Code: raw JSONL bytes
 29→	//   - Cursor: serialized SQLite rows
 30→	//   - Aider: Markdown content
 31→	NativeData []byte
 32→
 33→	// Computed fields - populated by the agent when reading
 34→	ModifiedFiles []string
 35→	NewFiles      []string
 36→	DeletedFiles  []string
 37→
 38→	// Optional normalized entries - agents may populate this if needed
 39→	// for operations that benefit from structured access
 40→	Entries []SessionEntry
 41→}
 42→
 43→// SessionEntry represents a single entry in the session
 44→type SessionEntry struct {
 45→	UUID      string
 46→	Type      EntryType
 47→	Timestamp time.Time
 48→	Content   string
 49→
 50→	// Tool-specific fields
 51→	ToolName      string
 52→	ToolInput     interface{}
 53→	ToolOutput    interface{}
 54→	FilesAffected []string
 55→}
 56→
 57→// EntryType categorizes session entries
 58→type EntryType string
 59→
 60→const (
 61→	EntryUser      EntryType = "user"
 62→	EntryAssistant EntryType = "assistant"
 63→	EntryTool      EntryType = "tool"
 64→	EntrySystem    EntryType = "system"
 65→)
 66→
 67→// GetLastUserPrompt returns the last user message content
 68→func (s *AgentSession) GetLastUserPrompt() string {
 69→	for i := len(s.Entries) - 1; i >= 0; i-- {
 70→		if s.Entries[i].Type == EntryUser {
 71→			return s.Entries[i].Content
 72→		}
 73→	}
 74→	return ""
 75→}
 76→
 77→// GetLastAssistantResponse returns the last assistant message content
 78→func (s *AgentSession) GetLastAssistantResponse() string {
 79→	for i := len(s.Entries) - 1; i >= 0; i-- {
 80→		if s.Entries[i].Type == EntryAssistant {
 81→			return s.Entries[i].Content
 82→		}
 83→	}
 84→	return ""
 85→}
 86→
 87→// TruncateAtUUID returns a new session truncated at the given UUID (inclusive)
 88→func (s *AgentSession) TruncateAtUUID(uuid string) *AgentSession {
 89→	if uuid == "" {
 90→		return s
 91→	}
 92→
 93→	truncated := &AgentSession{
 94→		SessionID:  s.SessionID,
 95→		AgentName:  s.AgentName,
 96→		RepoPath:   s.RepoPath,
 97→		SessionRef: s.SessionRef,
 98→		StartTime:  s.StartTime,
 99→	}
100→
101→	for i, entry := range s.Entries {
102→		truncated.Entries = append(truncated.Entries, entry)
103→		if entry.UUID == uuid {
104→			truncated.Entries = s.Entries[:i+1]
105→			break
106→		}
107→	}
108→
109→	// Recompute file lists from truncated entries
110→	fileSet := make(map[string]bool)
111→	for _, entry := range truncated.Entries {
112→		for _, f := range entry.FilesAffected {
113→			if !fileSet[f] {
114→				fileSet[f] = true
115→				truncated.ModifiedFiles = append(truncated.ModifiedFiles, f)
116→			}
117→		}
118→	}
119→
120→	return truncated
121→}
122→
123→// FindToolResultUUID finds the UUID of the entry containing the tool result
124→// for the given tool use ID. Returns the UUID and true if found.
125→func (s *AgentSession) FindToolResultUUID(toolUseID string) (string, bool) {
126→	for _, entry := range s.Entries {
127→		if entry.Type == EntryTool && entry.UUID == toolUseID {
128→			return entry.UUID, true
129→		}
130→	}
131→	return "", false
132→}
