 13→
 14→// TestAgentPackages_NoForbiddenImports verifies that agent implementation packages
 15→// (claudecode, geminicli, opencode, cursor, etc.) only import from allowed packages.
 16→//
 17→// This prevents agent implementations from coupling to framework internals
 18→// (strategy, checkpoint, session, commands, hook_registry, lifecycle) which
 19→// would create brittle dependencies that break when internals change.
 20→//
 21→// Agents should depend only on:
 22→//   - The agent contract package (agent, agent/types, agent/testutil)
 23→//   - Utility packages (logging, paths, jsonutil, textutil, transcript, etc.)
 24→//   - Standard library and external dependencies
 25→func TestAgentPackages_NoForbiddenImports(t *testing.T) {
 26→	t.Parallel()
 27→
 28→	const repoPrefix = "github.com/entireio/cli/cmd/entire/cli/"
 29→
 30→	// Packages that agent implementations must NOT import.
 31→	// These are framework internals that agents should be decoupled from.
 32→	forbiddenSuffixes := []string{
 33→		"strategy",
 34→		"checkpoint",
 35→		"session",
 36→		"commands",
 37→	}
 38→
 39→	// Individual files in the cli package that agents must not depend on.
 40→	// We check for the cli package import itself since these are all in
 41→	// the top-level cli package (not sub-packages).
 42→	forbiddenCLIPackage := repoPrefix[:len(repoPrefix)-1] // "github.com/entireio/cli/cmd/entire/cli"
 43→
 44→	// Packages within the repo that agents ARE allowed to import.
 45→	allowedPrefixes := []string{
 46→		repoPrefix + "agent",      // agent contract + sub-packages
 47→		repoPrefix + "logging",    // logging utilities
 48→		repoPrefix + "paths",      // path utilities
 49→		repoPrefix + "jsonutil",   // JSON utilities
 50→		repoPrefix + "textutil",   // text utilities
 51→		repoPrefix + "transcript", // transcript utilities
 52→		repoPrefix + "trailers",   // git trailer utilities
 53→		repoPrefix + "stringutil", // string utilities
 54→		repoPrefix + "telemetry",  // telemetry
 55→		repoPrefix + "validation", // validation utilities
 56→		repoPrefix + "settings",   // settings (read-only access)
 57→	}
 58→
 59→	agentDir := findAgentDir(t)
 60→	agentPkgs := discoverAgentPackages(t, agentDir)
 61→
 62→	if len(agentPkgs) == 0 {
 63→		t.Fatal("no agent packages found — test setup is broken")
 64→	}
 65→
 66→	for _, pkgDir := range agentPkgs {
 67→		pkgName := filepath.Base(pkgDir)
 68→		t.Run(pkgName, func(t *testing.T) {
 69→			t.Parallel()
 70→			imports := extractImports(t, pkgDir)
 71→			for _, imp := range imports {
 72→				if !strings.HasPrefix(imp, repoPrefix) && imp != forbiddenCLIPackage {
 73→					continue // external or stdlib — allowed
 74→				}
 75→
 76→				// Check if it's the top-level cli package itself
 77→				if imp == forbiddenCLIPackage {
 78→					t.Errorf("forbidden import %q — agent packages must not import the top-level cli package directly", imp)
 79→					continue
 80→				}
 81→
 82→				// Check forbidden suffixes
 83→				rel := strings.TrimPrefix(imp, repoPrefix)
 84→				isForbidden := false
 85→				for _, forbidden := range forbiddenSuffixes {
 86→					if rel == forbidden || strings.HasPrefix(rel, forbidden+"/") {
 87→						t.Errorf("forbidden import %q — agent packages must not import %s internals", imp, forbidden)
 88→						isForbidden = true
 89→					}
 90→				}
 91→				if isForbidden {
 92→					continue
 93→				}
 94→
 95→				// Check it's in the allowed list
 96→				allowed := false
 97→				for _, prefix := range allowedPrefixes {
 98→					if imp == prefix || strings.HasPrefix(imp, prefix+"/") {
 99→						allowed = true
100→						break
101→					}
102→				}
103→				if !allowed {
104→					t.Errorf("unexpected internal import %q — if this is intentional, add it to allowedPrefixes in architecture_test.go", imp)
105→				}
106→			}
107→		})
108→	}
109→}
