111→// findAgentDir returns the absolute path to cmd/entire/cli/agent/.
112→// Go test runner sets cwd to the package directory, so os.Getwd() gives us
113→// the agent dir directly.
114→func findAgentDir(t *testing.T) string {
115→	t.Helper()
116→	wd, err := os.Getwd()
117→	if err != nil {
118→		t.Fatalf("os.Getwd: %v", err)
119→	}
120→	return wd
121→}
122→
123→// discoverAgentPackages finds all subdirectories of the agent dir that contain
124→// Go files, excluding "types" and "testutil" (those are contract/shared packages).
125→func discoverAgentPackages(t *testing.T, agentDir string) []string {
126→	t.Helper()
127→
128→	skipDirs := map[string]bool{
129→		"types":    true, // contract types, not an agent implementation
130→		"testutil": true, // shared test utilities
131→	}
132→
133→	entries, err := os.ReadDir(agentDir)
134→	if err != nil {
135→		t.Fatalf("ReadDir(%s): %v", agentDir, err)
136→	}
137→
138→	var pkgs []string
139→	for _, e := range entries {
140→		if !e.IsDir() || skipDirs[e.Name()] {
141→			continue
142→		}
143→		dir := filepath.Join(agentDir, e.Name())
144→		// Only include if it has Go files
145→		goFiles, err := filepath.Glob(filepath.Join(dir, "*.go"))
146→		if err != nil {
147→			t.Fatalf("filepath.Glob(%s): %v", dir, err)
148→		}
149→		if len(goFiles) > 0 {
150→			pkgs = append(pkgs, dir)
151→		}
152→	}
153→	return pkgs
154→}
155→
156→// extractImports parses all Go files in a directory and returns unique import paths.
157→// Includes both production and test files — test-only imports should also respect boundaries.
158→func extractImports(t *testing.T, dir string) []string {
159→	t.Helper()
160→
161→	fset := token.NewFileSet()
162→	//nolint:staticcheck // ParseDir is deprecated in favor of go/packages, but we intentionally
163→	// scan all files regardless of build tags to catch forbidden imports in test files too.
164→	pkgs, err := parser.ParseDir(fset, dir, nil, parser.ImportsOnly)
165→	if err != nil {
166→		t.Fatalf("parser.ParseDir(%s): %v", dir, err)
167→	}
168→
169→	seen := make(map[string]bool)
170→	for _, pkg := range pkgs {
171→		for _, file := range pkg.Files {
172→			for _, imp := range file.Imports {
173→				path, err := strconv.Unquote(imp.Path.Value)
174→				if err != nil {
175→					t.Fatalf("strconv.Unquote(%s): %v", imp.Path.Value, err)
176→				}
177→				seen[path] = true
178→			}
179→		}
180→	}
181→
182→	imports := make([]string, 0, len(seen))
183→	for imp := range seen {
184→		imports = append(imports, imp)
185→	}
186→	return imports
187→}
