189→// TestAgentPackages_SelfRegister verifies that each agent package has an init()
190→// function that calls agent.Register(). This ensures agents are properly
191→// discoverable via the registry.
192→func TestAgentPackages_SelfRegister(t *testing.T) {
193→	t.Parallel()
194→
195→	agentDir := findAgentDir(t)
196→	agentPkgs := discoverAgentPackages(t, agentDir)
197→
198→	if len(agentPkgs) == 0 {
199→		t.Fatal("no agent packages found — test setup is broken")
200→	}
201→
202→	for _, pkgDir := range agentPkgs {
203→		pkgName := filepath.Base(pkgDir)
204→		t.Run(pkgName, func(t *testing.T) {
205→			t.Parallel()
206→			if !hasInitWithRegister(t, pkgDir) {
207→				t.Errorf("agent package %q has no init() function calling Register() — agents must self-register", pkgName)
208→			}
209→		})
210→	}
211→}
212→
213→// hasInitWithRegister checks if any Go file in the directory has an init()
214→// function that contains a call to Register.
215→func hasInitWithRegister(t *testing.T, dir string) bool {
216→	t.Helper()
217→
218→	fset := token.NewFileSet()
219→	//nolint:staticcheck // See extractImports for rationale.
220→	pkgs, err := parser.ParseDir(fset, dir, func(fi os.FileInfo) bool {
221→		return !strings.HasSuffix(fi.Name(), "_test.go")
222→	}, 0)
223→	if err != nil {
224→		t.Fatalf("parser.ParseDir(%s): %v", dir, err)
225→	}
226→
227→	for _, pkg := range pkgs {
228→		for _, file := range pkg.Files {
229→			for _, decl := range file.Decls {
230→				fn, ok := decl.(*ast.FuncDecl)
231→				if !ok || fn.Name.Name != "init" || fn.Recv != nil {
232→					continue
233→				}
234→				// Walk the init body looking for a call to Register or agent.Register
235→				found := false
236→				ast.Inspect(fn.Body, func(n ast.Node) bool {
237→					call, ok := n.(*ast.CallExpr)
238→					if !ok {
239→						return true
240→					}
241→					switch fun := call.Fun.(type) {
242→					case *ast.Ident:
243→						if fun.Name == "Register" {
244→							found = true
245→						}
246→					case *ast.SelectorExpr:
247→						if fun.Sel.Name == "Register" {
248→							found = true
249→						}
250→					}
251→					return !found
252→				})
253→				if found {
254→					return true
255→				}
256→			}
257→		}
258→	}
259→	return false
260→}
