 19→// calculateTokenUsage is a test helper that looks up the Factory AI Droid agent
 20→// and calculates token usage from pre-loaded transcript bytes.
 21→func calculateTokenUsage(_ types.AgentType, data []byte, offset int) *agent.TokenUsage {
 22→	ag, err := agent.GetByAgentType(agent.AgentTypeFactoryAIDroid)
 23→	if err != nil {
 24→		return nil
 25→	}
 26→	return agent.CalculateTokenUsage(context.Background(), ag, data, offset, "")
 27→}
