 29→func TestCalculateTokenUsage_CursorReturnsNil(t *testing.T) {
 30→	t.Parallel()
 31→
 32→	// Cursor transcripts don't contain token usage data, so CalculateTokenUsage
 33→	// should return nil (not an empty struct) to signal "no data available".
 34→	transcript := []byte(`{"role":"user","message":{"content":[{"type":"text","text":"hello"}]}}`)
 35→
 36→	ag, err := agent.GetByAgentType(agent.AgentTypeCursor)
 37→	if err != nil {
 38→		t.Fatalf("GetByAgentType(Cursor) error: %v", err)
 39→	}
 40→	result := agent.CalculateTokenUsage(context.Background(), ag, transcript, 0, "")
 41→	if result != nil {
 42→		t.Errorf("CalculateTokenUsage(Cursor) = %+v, want nil", result)
 43→	}
 44→}
