 46→func TestCalculateTokenUsage_EmptyData(t *testing.T) {
 47→	t.Parallel()
 48→
 49→	ag, err := agent.GetByAgentType(agent.AgentTypeClaudeCode)
 50→	if err != nil {
 51→		t.Fatalf("GetByAgentType(ClaudeCode) error: %v", err)
 52→	}
 53→	result := agent.CalculateTokenUsage(context.Background(), ag, nil, 0, "")
 54→	if result == nil {
 55→		t.Fatal("CalculateTokenUsage(empty) = nil, want non-nil empty struct")
 56→	}
 57→	if result.InputTokens != 0 || result.OutputTokens != 0 {
 58→		t.Errorf("expected zero tokens for empty data, got %+v", result)
 59→	}
 60→}
