 62→func TestCalculateTokenUsage_ClaudeCodeBasic(t *testing.T) {
 63→	t.Parallel()
 64→
 65→	// Claude Code JSONL: "usage" with "id" lives inside the "message" JSON object
 66→	lines := []string{
 67→		`{"type":"human","uuid":"u1","message":{"content":"hello"}}`,
 68→		`{"type":"assistant","uuid":"u2","message":{"id":"msg_001","usage":{"input_tokens":10,"output_tokens":5}}}`,
 69→	}
 70→	data := []byte(strings.Join(lines, "\n") + "\n")
 71→
 72→	ag, err := agent.GetByAgentType(agent.AgentTypeClaudeCode)
 73→	if err != nil {
 74→		t.Fatalf("GetByAgentType(ClaudeCode) error: %v", err)
 75→	}
 76→	result := agent.CalculateTokenUsage(context.Background(), ag, data, 0, "")
 77→	if result == nil {
 78→		t.Fatal("CalculateTokenUsage(ClaudeCode) = nil, want non-nil")
 79→	}
 80→	if result.OutputTokens != 5 {
 81→		t.Errorf("OutputTokens = %d, want 5", result.OutputTokens)
 82→	}
 83→	if result.APICallCount != 1 {
 84→		t.Errorf("APICallCount = %d, want 1", result.APICallCount)
 85→	}
 86→}
