 88→func TestCalculateTokenUsage_ClaudeCodeWithOffset(t *testing.T) {
 89→	t.Parallel()
 90→
 91→	// 4-line transcript; start at offset 2 to only count the second pair
 92→	lines := []string{
 93→		`{"type":"human","uuid":"u1","message":{"content":"first"}}`,
 94→		`{"type":"assistant","uuid":"u2","message":{"id":"msg_001","usage":{"input_tokens":10,"output_tokens":5}}}`,
 95→		`{"type":"human","uuid":"u3","message":{"content":"second"}}`,
 96→		`{"type":"assistant","uuid":"u4","message":{"id":"msg_002","usage":{"input_tokens":20,"output_tokens":15}}}`,
 97→	}
 98→	data := []byte(strings.Join(lines, "\n") + "\n")
 99→
100→	ag, err := agent.GetByAgentType(agent.AgentTypeClaudeCode)
101→	if err != nil {
102→		t.Fatalf("GetByAgentType(ClaudeCode) error: %v", err)
103→	}
104→	full := agent.CalculateTokenUsage(context.Background(), ag, data, 0, "")
105→	sliced := agent.CalculateTokenUsage(context.Background(), ag, data, 2, "")
106→
107→	if full == nil || sliced == nil {
108→		t.Fatal("expected non-nil results")
109→	}
110→	if full.OutputTokens != 20 {
111→		t.Errorf("full OutputTokens = %d, want 20", full.OutputTokens)
112→	}
113→	if sliced.OutputTokens != 15 {
114→		t.Errorf("sliced OutputTokens = %d, want 15", sliced.OutputTokens)
115→	}
116→}
