148→func TestExtractUserPrompts_Cursor(t *testing.T) {
149→	t.Parallel()
150→
151→	// Cursor uses "role":"user" instead of "type":"human". extractUserPromptsFromLines
152→	// handles both via the "role" fallback.
153→	prompts := extractUserPrompts(agent.AgentTypeCursor, cursorSampleTranscript)
154→	if len(prompts) != 3 {
155→		t.Fatalf("extractUserPrompts(Cursor) returned %d prompts, want 3", len(prompts))
156→	}
157→
158→	if !strings.Contains(prompts[0], "create a file with contents 'a'") {
159→		t.Errorf("prompt[0] = %q, expected to contain file creation request", prompts[0])
160→	}
