162→		t.Errorf("prompt[2] = %q, expected to contain 'bingo'", prompts[2])
163→	}
164→
165→	// Verify <user_query> tags are stripped
166→	for i, p := range prompts {
167→		if strings.Contains(p, "<user_query>") || strings.Contains(p, "</user_query>") {
168→			t.Errorf("prompt[%d] still contains <user_query> tags: %q", i, p)
169→		}
170→	}
