// to cache its metadata. Returns an error if the binary cannot be invoked or returns
// invalid/incompatible protocol data.
func NewExternalAgent(binaryPath string) (*ExternalAgent, error) {
	ea := &ExternalAgent{binaryPath: binaryPath}

	stdout, err := ea.run(context.Background(), nil, "info")
	if err != nil {
		return nil, fmt.Errorf("info: %w", err)
	}

	var info InfoResponse
	if err := json.Unmarshal(stdout, &info); err != nil {
		return nil, fmt.Errorf("info: invalid JSON: %w", err)
	}

	if info.ProtocolVersion != ProtocolVersion {
		return nil, fmt.Errorf("protocol version mismatch: binary reports %d, expected %d",
			info.ProtocolVersion, ProtocolVersion)
	}

	ea.info = &info
	return ea, nil
}

