// run executes a subcommand on the external binary and returns stdout bytes.
// If stdin is non-nil it is piped to the process. On non-zero exit, stderr is
// included in the returned error.
func (e *ExternalAgent) run(ctx context.Context, stdin []byte, args ...string) ([]byte, error) {
	cmd := exec.CommandContext(ctx, e.binaryPath, args...)

	// Set environment: repo root + protocol version
	cmd.Env = append(cmd.Environ(),
		"ENTIRE_PROTOCOL_VERSION="+strconv.Itoa(ProtocolVersion),
	)
	if repoRoot, err := paths.WorktreeRoot(); err == nil {
		cmd.Env = append(cmd.Env, "ENTIRE_REPO_ROOT="+repoRoot)
		cmd.Dir = repoRoot
	}

	if stdin != nil {
		cmd.Stdin = bytes.NewReader(stdin)
	}

	var stdoutBuf, stderrBuf bytes.Buffer
	cmd.Stdout = &stdoutBuf
	cmd.Stderr = &stderrBuf

	if err := cmd.Run(); err != nil {
		errMsg := stderrBuf.String()
		if errMsg != "" {
			return nil, fmt.Errorf("%s: %s", args[0], errMsg)
		}
		return nil, fmt.Errorf("%s: %w", args[0], err)
	}

	return stdoutBuf.Bytes(), nil
}

// --- Helpers ---

func marshalHookInput(input *agent.HookInput) ([]byte, error) {
	if input == nil {
		return []byte("{}"), nil
	}
	j := HookInputJSON{
		HookType:   string(input.HookType),
		SessionID:  input.SessionID,
		SessionRef: input.SessionRef,
		Timestamp:  input.Timestamp.Format(time.RFC3339),
		UserPrompt: input.UserPrompt,
		ToolName:   input.ToolName,
		ToolUseID:  input.ToolUseID,
		ToolInput:  input.ToolInput,
		RawData:    input.RawData,
	}
	return json.Marshal(j)
}

func marshalAgentSession(s *agent.AgentSession) ([]byte, error) {
	j := AgentSessionJSON{
		SessionID:     s.SessionID,
		AgentName:     string(s.AgentName),
		RepoPath:      s.RepoPath,
		SessionRef:    s.SessionRef,
		StartTime:     s.StartTime.Format(time.RFC3339),
		NativeData:    s.NativeData,
		ModifiedFiles: s.ModifiedFiles,
		NewFiles:      s.NewFiles,
		DeletedFiles:  s.DeletedFiles,
	}
	return json.Marshal(j)
}

func unmarshalAgentSession(j *AgentSessionJSON) (*agent.AgentSession, error) {
	var startTime time.Time
	if j.StartTime != "" {
		var err error
		startTime, err = time.Parse(time.RFC3339, j.StartTime)
		if err != nil {
			return nil, fmt.Errorf("invalid start_time: %w", err)
		}
	}
	return &agent.AgentSession{
		SessionID:     j.SessionID,
		AgentName:     types.AgentName(j.AgentName),
		RepoPath:      j.RepoPath,
		SessionRef:    j.SessionRef,
		StartTime:     startTime,
		NativeData:    j.NativeData,
		ModifiedFiles: j.ModifiedFiles,
		NewFiles:      j.NewFiles,
		DeletedFiles:  j.DeletedFiles,
	}, nil
}

func convertTokenUsage(r *TokenUsageResponse) *agent.TokenUsage {
	if r == nil {
		return nil
	}
	usage := &agent.TokenUsage{
		InputTokens:         r.InputTokens,
		CacheCreationTokens: r.CacheCreationTokens,
		CacheReadTokens:     r.CacheReadTokens,
		OutputTokens:        r.OutputTokens,
		APICallCount:        r.APICallCount,
	}
	if r.SubagentTokens != nil {
		usage.SubagentTokens = convertTokenUsage(r.SubagentTokens)
	}
	return usage
}

package external

import (
	"github.com/entireio/cli/cmd/entire/cli/agent"
)

// Wrap returns the ExternalAgent wrapped with the appropriate interface
// implementations based on the capabilities declared in its info response.
// The returned value satisfies agent.Agent and whichever optional interfaces
// the external binary declared support for.
func Wrap(ea *ExternalAgent) agent.Agent {
	caps := ea.info.Capabilities

	// Build the combination based on capabilities.
	// We use a set of wrapper types that embed ExternalAgent and declare the
	// optional interfaces. Go's type assertion checks are structural, so the
	// returned value will satisfy the right set of interfaces.
	//
	// The most common combinations get dedicated types to avoid excessive
	// allocations. For rare combinations, we compose at runtime.

	switch {
	case caps.Hooks && caps.TranscriptAnalyzer && caps.TokenCalculator && caps.TextGenerator && caps.HookResponseWriter && caps.SubagentAwareExtractor:
		return &fullAgent{ExternalAgent: ea}
	case caps.Hooks && caps.TranscriptAnalyzer:
		return &hooksAnalyzerAgent{ExternalAgent: ea}
	case caps.Hooks:
		return &hooksAgent{ExternalAgent: ea}
	case caps.TranscriptAnalyzer:
		return &analyzerAgent{ExternalAgent: ea}
	default:
		return ea
	}
}

// --- Wrapper types for interface composition ---

// hooksAgent wraps ExternalAgent for agents that support hooks only.
type hooksAgent struct {
	*ExternalAgent
}

// Verify interface compliance at compile time.
var _ agent.HookSupport = (*hooksAgent)(nil)

// hooksAnalyzerAgent wraps ExternalAgent for agents that support hooks + transcript analysis.
type hooksAnalyzerAgent struct {
	*ExternalAgent
}

var (
	_ agent.HookSupport       = (*hooksAnalyzerAgent)(nil)
	_ agent.TranscriptAnalyzer = (*hooksAnalyzerAgent)(nil)
)

// analyzerAgent wraps ExternalAgent for agents that support transcript analysis only.
type analyzerAgent struct {
	*ExternalAgent
}

var _ agent.TranscriptAnalyzer = (*analyzerAgent)(nil)

// fullAgent wraps ExternalAgent for agents that support all optional interfaces.
type fullAgent struct {
	*ExternalAgent
}

var (
	_ agent.HookSupport            = (*fullAgent)(nil)
	_ agent.TranscriptAnalyzer     = (*fullAgent)(nil)
	_ agent.TokenCalculator        = (*fullAgent)(nil)
	_ agent.TextGenerator          = (*fullAgent)(nil)
	_ agent.HookResponseWriter     = (*fullAgent)(nil)
	_ agent.SubagentAwareExtractor = (*fullAgent)(nil)
)

