	}
	if string(ea.Type()) != "Test Agent" {
		t.Errorf("Type() = %q, want %q", ea.Type(), "Test Agent")
	}
	if ea.Description() != "A test agent" {
		t.Errorf("Description() = %q, want %q", ea.Description(), "A test agent")
