330→// droidMessage builds a Droid JSONL "message" line with the given id, role, and optional usage.
331→func droidMessage(t *testing.T, id, role string, usage map[string]int) string {
332→	t.Helper()
333→	inner := map[string]interface{}{
334→		"role":    role,
335→		"content": []interface{}{},
336→	}
337→	if usage != nil {
338→		inner["id"] = id
339→		inner["usage"] = usage
340→	}
341→	msg, err := json.Marshal(inner)
342→	if err != nil {
343→		t.Fatalf("failed to marshal inner message: %v", err)
344→	}
345→	line := map[string]interface{}{
346→		"type":    "message",
347→		"id":      id,
348→		"message": json.RawMessage(msg),
349→	}
350→	b, err := json.Marshal(line)
351→	if err != nil {
352→		t.Fatalf("failed to marshal droid line: %v", err)
353→	}
354→	return string(b)
355→}
