357→func TestCalculateTokenUsage_DroidStartOffsetSkipsNonMessageLines(t *testing.T) {
358→	t.Parallel()
359→
360→	// Build a Droid transcript with non-message entries interspersed:
361→	// Line 0: session_start (non-message)
362→	// Line 1: user message (no tokens)
363→	// Line 2: assistant message with 10 input, 20 output tokens
364→	// Line 3: session_event (non-message)
365→	// Line 4: assistant message with 5 input, 30 output tokens
366→	transcript := "" +
367→		`{"type":"session_start","id":"s1"}` + "\n" +
368→		droidMessage(t, "m1", "user", nil) + "\n" +
369→		droidMessage(t, "m2", "assistant", map[string]int{
370→			"input_tokens": 10, "output_tokens": 20,
371→		}) + "\n" +
372→		`{"type":"session_event","data":"heartbeat"}` + "\n" +
373→		droidMessage(t, "m3", "assistant", map[string]int{
374→			"input_tokens": 5, "output_tokens": 30,
375→		}) + "\n"
376→
377→	data := []byte(transcript)
378→
379→	// With startOffset=0: should count all messages (m2 + m3)
380→	usageAll := calculateTokenUsage(agent.AgentTypeFactoryAIDroid, data, 0)
381→	if usageAll.InputTokens != 15 {
382→		t.Errorf("startOffset=0: InputTokens = %d, want 15", usageAll.InputTokens)
383→	}
384→	if usageAll.OutputTokens != 50 {
385→		t.Errorf("startOffset=0: OutputTokens = %d, want 50", usageAll.OutputTokens)
386→	}
387→	if usageAll.APICallCount != 2 {
388→		t.Errorf("startOffset=0: APICallCount = %d, want 2", usageAll.APICallCount)
389→	}
390→
391→	// With startOffset=3: skip lines 0-2 (session_start, m1, m2).
392→	// Only line 3 (session_event, filtered) and line 4 (m3) remain.
393→	// Should count only m3's tokens.
