400→	}
401→	if usageFrom3.APICallCount != 1 {
402→		t.Errorf("startOffset=3: APICallCount = %d, want 1", usageFrom3.APICallCount)
403→	}
404→
405→	// Regression: using the OLD buggy code would have parsed all messages (ignoring
406→	// non-message entries), producing [m1, m2, m3], then sliced at index 3 which
407→	// is out of bounds — returning all tokens instead of just m3's.
408→	// With startOffset=1: skip only line 0 (session_start).
409→	// Lines 1 (m1), 2 (m2), 3 (session_event, filtered), 4 (m3) remain.
410→	usageFrom1 := calculateTokenUsage(agent.AgentTypeFactoryAIDroid, data, 1)
411→	if usageFrom1.InputTokens != 15 {
412→		t.Errorf("startOffset=1: InputTokens = %d, want 15", usageFrom1.InputTokens)
413→	}
414→	if usageFrom1.APICallCount != 2 {
415→		t.Errorf("startOffset=1: APICallCount = %d, want 2", usageFrom1.APICallCount)
416→	}
417→}
