 18→// ExternalAgent implements agent.Agent by delegating to an external binary.
 19→// Each method invokes a subcommand on the binary and parses the JSON response.
 20→type ExternalAgent struct {
 21→	binaryPath string
 22→	info       *InfoResponse
 23→}
 24→
 25→// NewExternalAgent creates an ExternalAgent by calling the binary's "info" subcommand
 26→// to cache its metadata. Returns an error if the binary cannot be invoked or returns
 27→// invalid/incompatible protocol data.
 28→func NewExternalAgent(binaryPath string) (*ExternalAgent, error) {
 29→	ea := &ExternalAgent{binaryPath: binaryPath}
 30→
 31→	stdout, err := ea.run(context.Background(), nil, "info")
 32→	if err != nil {
 33→		return nil, fmt.Errorf("info: %w", err)
 34→	}
 35→
 36→	var info InfoResponse
 37→	if err := json.Unmarshal(stdout, &info); err != nil {
 38→		return nil, fmt.Errorf("info: invalid JSON: %w", err)
 39→	}
 40→
 41→	if info.ProtocolVersion != ProtocolVersion {
 42→		return nil, fmt.Errorf("protocol version mismatch: binary reports %d, expected %d",
 43→			info.ProtocolVersion, ProtocolVersion)
 44→	}
 45→
 46→	ea.info = &info
 47→	return ea, nil
 48→}
