package external

import (
	"github.com/entireio/cli/cmd/entire/cli/agent"
)

// Wrap returns the Agent wrapped with the appropriate interface
// implementations based on the capabilities declared in its info response.
// The returned value satisfies agent.Agent and whichever optional interfaces
// the external binary declared support for.
func Wrap(ea *Agent) agent.Agent {
	caps := ea.info.Capabilities

	// Build the combination based on capabilities.
	// We use a set of wrapper types that embed Agent and declare the
	// optional interfaces. Go's type assertion checks are structural, so the
	// returned value will satisfy the right set of interfaces.
	//
	// The most common combinations get dedicated types to avoid excessive
	// allocations. For rare combinations, we compose at runtime.

	switch {
	case caps.Hooks && caps.TranscriptAnalyzer && caps.TokenCalculator && caps.TextGenerator && caps.HookResponseWriter && caps.SubagentAwareExtractor:
		return &fullAgent{Agent: ea}
	case caps.Hooks && caps.TranscriptAnalyzer:
		return &hooksAnalyzerAgent{Agent: ea}
	case caps.Hooks:
		return &hooksAgent{Agent: ea}
	case caps.TranscriptAnalyzer:
		return &analyzerAgent{Agent: ea}
	default:
		return ea
	}
}

// --- Wrapper types for interface composition ---

// hooksAgent wraps Agent for agents that support hooks only.
type hooksAgent struct {
	*Agent
}

// Verify interface compliance at compile time.
var _ agent.HookSupport = (*hooksAgent)(nil)

// hooksAnalyzerAgent wraps Agent for agents that support hooks + transcript analysis.
type hooksAnalyzerAgent struct {
	*Agent
}

var (
	_ agent.HookSupport        = (*hooksAnalyzerAgent)(nil)
	_ agent.TranscriptAnalyzer = (*hooksAnalyzerAgent)(nil)
)

// analyzerAgent wraps Agent for agents that support transcript analysis only.
type analyzerAgent struct {
	*Agent
}

var _ agent.TranscriptAnalyzer = (*analyzerAgent)(nil)

// fullAgent wraps Agent for agents that support all optional interfaces.
type fullAgent struct {
	*Agent
}

var (
	_ agent.HookSupport            = (*fullAgent)(nil)
	_ agent.TranscriptAnalyzer     = (*fullAgent)(nil)
	_ agent.TokenCalculator        = (*fullAgent)(nil)
	_ agent.TextGenerator          = (*fullAgent)(nil)
	_ agent.HookResponseWriter     = (*fullAgent)(nil)
	_ agent.SubagentAwareExtractor = (*fullAgent)(nil)
)

