110→// SliceFromLine returns the content starting from line number `startLine` (0-indexed).
111→// This is used to extract only the checkpoint-specific portion of a cumulative transcript.
112→// For example, if startLine is 2, lines 0 and 1 are skipped and the result starts at line 2.
113→// Returns empty slice if startLine exceeds the number of lines.
114→func SliceFromLine(content []byte, startLine int) []byte {
115→	if len(content) == 0 || startLine <= 0 {
116→		return content
117→	}
118→
119→	// Find the byte offset where startLine begins
120→	lineCount := 0
121→	offset := 0
122→	for i, b := range content {
123→		if b == '\n' {
124→			lineCount++
125→			if lineCount == startLine {
126→				offset = i + 1
127→				break
128→			}
129→		}
130→	}
131→
132→	// If we didn't find enough lines, return empty
133→	if lineCount < startLine {
134→		return nil
135→	}
136→
137→	// If offset is beyond content, return empty
138→	if offset >= len(content) {
139→		return nil
140→	}
141→
142→	return content[offset:]
143→}
144→
145→// ExtractUserContent extracts user content from a raw message.
146→// Handles both string and array content formats.
147→// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
148→// Returns empty string if the message cannot be parsed or contains no text.
149→func ExtractUserContent(message json.RawMessage) string {
150→	var msg UserMessage
151→	if err := json.Unmarshal(message, &msg); err != nil {
152→		return ""
153→	}
154→
155→	// Handle string content
156→	if str, ok := msg.Content.(string); ok {
157→		return textutil.StripIDEContextTags(str)
158→	}
159→
160→	// Handle array content (only if it contains text blocks)
161→	if arr, ok := msg.Content.([]interface{}); ok {
162→		var texts []string
163→		for _, item := range arr {
164→			if m, ok := item.(map[string]interface{}); ok {
165→				if m["type"] == ContentTypeText {
166→					if text, ok := m["text"].(string); ok {
167→						texts = append(texts, text)
168→					}
169→				}
170→			}
171→		}
172→		if len(texts) > 0 {
173→			return textutil.StripIDEContextTags(strings.Join(texts, "\n\n"))
174→		}
175→	}
176→
177→	return ""
178→}
