 13→const (
 14→	// MaxChunkSize is the maximum size for a single transcript chunk.
 15→	// GitHub has a 100MB limit per blob, so we use 50MB to be safe.
 16→	MaxChunkSize = 50 * 1024 * 1024 // 50MB
 17→
 18→	// ChunkSuffix is the format for chunk file suffixes (e.g., ".001", ".002")
 19→	ChunkSuffix = ".%03d"
 20→)
 21→
 22→// ChunkTranscript splits a transcript into chunks using the appropriate agent.
 23→// If agentType is empty or the agent is not found, falls back to JSONL (line-based) chunking.
 24→func ChunkTranscript(ctx context.Context, content []byte, agentType types.AgentType) ([][]byte, error) {
 25→	if len(content) <= MaxChunkSize {
 26→		return [][]byte{content}, nil
 27→	}
 28→
 29→	// Try to get the agent by type and use its format-aware chunking
 30→	if agentType != "" {
 31→		ag, err := GetByAgentType(agentType)
 32→		if err == nil {
 33→			chunks, chunkErr := ag.ChunkTranscript(ctx, content, MaxChunkSize)
 34→			if chunkErr != nil {
 35→				return nil, fmt.Errorf("agent chunking failed: %w", chunkErr)
 36→			}
 37→			return chunks, nil
 38→		}
 39→	}
 40→
 41→	// Fall back to JSONL chunking (default)
 42→	return ChunkJSONL(content, MaxChunkSize)
 43→}
 44→
 45→// ReassembleTranscript combines chunks back into a single transcript.
 46→// If agentType is empty or the agent is not found, falls back to JSONL (line-based) reassembly.
 47→func ReassembleTranscript(chunks [][]byte, agentType types.AgentType) ([]byte, error) {
 48→	if len(chunks) == 0 {
 49→		return nil, nil
 50→	}
 51→	if len(chunks) == 1 {
 52→		return chunks[0], nil
 53→	}
 54→
 55→	// Try to get the agent by type and use its format-aware reassembly
 56→	if agentType != "" {
 57→		ag, err := GetByAgentType(agentType)
 58→		if err == nil {
 59→			result, reassembleErr := ag.ReassembleTranscript(chunks)
 60→			if reassembleErr != nil {
 61→				return nil, fmt.Errorf("agent reassembly failed: %w", reassembleErr)
 62→			}
 63→			return result, nil
 64→		}
 65→	}
 66→
 67→	// Fall back to JSONL reassembly (default)
 68→	return ReassembleJSONL(chunks), nil
 69→}
 70→
 71→// ChunkJSONL splits JSONL content at line boundaries.
 72→// This is the default chunking for agents using JSONL format (like Claude Code).
 73→func ChunkJSONL(content []byte, maxSize int) ([][]byte, error) {
 74→	// Handle empty content
 75→	if len(content) == 0 {
 76→		return [][]byte{}, nil
 77→	}
 78→
 79→	lines := strings.Split(string(content), "\n")
 80→	var chunks [][]byte
 81→	var currentChunk strings.Builder
 82→
 83→	for i, line := range lines {
 84→		// Check if adding this line would exceed the chunk size
 85→		lineWithNewline := line + "\n"
 86→
 87→		// Check if a single line exceeds maxSize - this is an error since we can't split JSONL lines
 88→		if len(lineWithNewline) > maxSize {
 89→			return nil, fmt.Errorf("JSONL line %d exceeds maximum chunk size (%d bytes > %d bytes); cannot split a single JSON object", i+1, len(lineWithNewline), maxSize)
 90→		}
 91→
 92→		if currentChunk.Len()+len(lineWithNewline) > maxSize && currentChunk.Len() > 0 {
 93→			// Save current chunk and start a new one
 94→			chunks = append(chunks, []byte(strings.TrimSuffix(currentChunk.String(), "\n")))
 95→			currentChunk.Reset()
 96→		}
 97→		currentChunk.WriteString(lineWithNewline)
 98→	}
 99→
100→	// Add the last chunk if it has content
101→	if currentChunk.Len() > 0 {
102→		chunks = append(chunks, []byte(strings.TrimSuffix(currentChunk.String(), "\n")))
103→	}
104→
105→	return chunks, nil
106→}
107→
108→// ReassembleJSONL concatenates JSONL chunks with newlines.
109→func ReassembleJSONL(chunks [][]byte) []byte {
110→	var result strings.Builder
111→	for i, chunk := range chunks {
112→		result.Write(chunk)
113→		if i < len(chunks)-1 {
114→			result.WriteString("\n")
115→		}
116→	}
117→	return []byte(result.String())
118→}
119→
120→// ChunkFileName returns the filename for a chunk at the given index.
121→// Index 0 returns the base filename, index 1+ returns with chunk suffix.
122→func ChunkFileName(baseName string, index int) string {
123→	if index == 0 {
124→		return baseName
125→	}
126→	return baseName + fmt.Sprintf(ChunkSuffix, index)
127→}
128→
129→// ParseChunkIndex extracts the chunk index from a filename.
130→// Returns 0 for the base file (no suffix), or the chunk number for suffixed files.
131→// Returns -1 if the filename doesn't match the expected pattern.
132→func ParseChunkIndex(filename, baseName string) int {
133→	if filename == baseName {
134→		return 0
135→	}
136→
137→	if !strings.HasPrefix(filename, baseName+".") {
138→		return -1
139→	}
140→
141→	suffix := strings.TrimPrefix(filename, baseName+".")
142→	var index int
143→	if _, err := fmt.Sscanf(suffix, "%03d", &index); err != nil {
144→		return -1
145→	}
146→	return index
147→}
148→
149→// SortChunkFiles sorts chunk filenames in order (base file first, then numbered chunks).
150→func SortChunkFiles(files []string, baseName string) []string {
151→	sorted := make([]string, len(files))
152→	copy(sorted, files)
153→
154→	sort.Slice(sorted, func(i, j int) bool {
155→		idxI := ParseChunkIndex(sorted[i], baseName)
156→		idxJ := ParseChunkIndex(sorted[j], baseName)
157→		return idxI < idxJ
158→	})
159→
160→	return sorted
161→}
