163→// geminiTranscriptDetect is used for detecting Gemini JSON format.
164→type geminiTranscriptDetect struct {
165→	Messages []interface{} `json:"messages"`
166→}
167→
168→// DetectAgentTypeFromContent detects the agent type from transcript content.
169→// Returns AgentTypeGemini if it appears to be Gemini JSON format, empty AgentType otherwise.
170→// This is used when the agent type is unknown but we need to chunk/reassemble correctly.
171→func DetectAgentTypeFromContent(content []byte) types.AgentType {
172→	// Quick check: Gemini JSON starts with { and has a messages array
173→	trimmed := strings.TrimSpace(string(content))
174→	if !strings.HasPrefix(trimmed, "{") {
175→		return ""
176→	}
177→
178→	// Try to parse as Gemini JSON format (object with messages array)
179→	var transcript geminiTranscriptDetect
180→	if err := json.Unmarshal(content, &transcript); err != nil {
181→		return ""
182→	}
183→
184→	// Must have at least one message to be considered Gemini format
185→	if len(transcript.Messages) > 0 {
186→		return AgentTypeGemini
187→	}
188→
189→	return ""
190→}
